svg.script:
{
  "@context": "https://schema.org",
  "@type": "HowTo",
  "name": "Email Warm-Up Ramp",
  "description": "How to gradually increase email sending volume during domain or IP warm-up, using engagement signals to guide each step.",
  "publisher": {
    "@type": "Organization",
    "name": "InboxAlly",
    "url": "https://www.inboxally.com"
  },
  "step": [
    {
      "@type": "HowToStep",
      "position": 1,
      "name": "Seed Phase (Weeks 1–2)",
      "text": "Begin sending at 2–5% of target volume. Focus on your most engaged subscribers. Target open rates above 30%. The goal is to establish baseline trust with mailbox providers."
    },
    {
      "@type": "HowToStep",
      "position": 2,
      "name": "Establish Phase (Weeks 2–3)",
      "text": "Increase to 10–20% of target volume. Expand to broader engaged segments. Maintain open rates above 25%. The goal is to build consistent positive engagement history."
    },
    {
      "@type": "HowToStep",
      "position": 3,
      "name": "Scale Phase (Weeks 4–5)",
      "text": "Increase to 35–75% of target volume. Begin sending to full list segments. Maintain open rates above 20%. The goal is to prove consistent engagement at meaningful volume."
    },
    {
      "@type": "HowToStep",
      "position": 4,
      "name": "Full Volume (Week 6+)",
      "text": "Reach 100% of target volume. Monitor engagement continuously. If metrics drop, reduce volume and investigate. The goal is to maintain healthy sending reputation long term."
    },
    {
      "@type": "HowToStep",
      "position": 5,
      "name": "Ongoing Monitoring",
      "text": "Warm-up is not a one-time process. Volume changes, new domains, and ESP migrations all require re-warming. Engagement must be monitored continuously to maintain reputation."
    }
  ]
}
